options.onRender:
try {
  const root = htmlNode;

  function getGrafanaVariableValue(variable) {
    return getTemplateSrv().replace(variable);
  }

  const plantNo = String(getGrafanaVariableValue("${plantNo}") || "7");
  const btNo = String(getGrafanaVariableValue("${tankNo}") || "BT01");

  const seriesList = data?.series || [];
  const liveSeries = seriesList.find(s => String(s.refId).toUpperCase() === "A");
  const trendSeries = seriesList.find(s => String(s.refId).toUpperCase() === "B");

  const safeNum = (v, d = NaN) => {
    const n = Number(v);
    return Number.isFinite(n) ? n : d;
  };

  const setText = (sel, val) => {
    const el = root.querySelector(sel);
    if (el) el.textContent = val;
  };

  const defer = (fn) => setTimeout(fn, 50);

  function getField(series, name) {
    if (!series?.fields) return null;

    const target = String(name).toLowerCase();

    return series.fields.find(f => {
      const fieldName = String(f.name || "").toLowerCase();
      return (
        fieldName === target ||
        fieldName.endsWith("." + target) ||
        fieldName.includes(target)
      );
    }) || null;
  }
  function getFirst(series, fieldName, fallback = null) {
    const f = getField(series, fieldName);
    if (!f) return fallback;
    return f.values?.get ? f.values.get(0) : (f.values?.[0] ?? fallback);
  }

  function getArray(field) {
    if (!field) return [];
    if (field.values?.toArray) return field.values.toArray();
    if (field.values?.buffer) return Array.from(field.values.buffer);
    if (Array.isArray(field.values)) return field.values;
    if (field.values?.get) {
      const arr = [];
      const len = field.values.length ?? 0;
      for (let i = 0; i < len; i++) arr.push(field.values.get(i));
      return arr;
    }
    return [];
  }

  function pickTimeField(series) {
    if (!series?.fields) return null;

    let f = series.fields.find(x => String(x.name).toLowerCase() === "_time");
    if (f) return f;

    f = series.fields.find(x => String(x.name).toLowerCase() === "time");
    if (f) return f;

    f = series.fields.find(x => x.type === "time");
    if (f) return f;

    return null;
  }

  function renderMiniTrendWithAxis({ el, times = [], value = [], min = [], max = [], lastEl, unit = "", yAxisLabel = String(unit || "").trim() }) {
    if (!el) return;

    const N = Math.min(value.length, min.length, max.length, times.length);
    if (N < 2) {
      el.innerHTML = "";
      if (lastEl) lastEl.textContent = "--";
      return;
    }

    const tArr = times.slice(0, N);
    const vArr = value.slice(0, N).map(Number);
    const loArr = min.slice(0, N).map(Number);
    const hiArr = max.slice(0, N).map(Number);

    const W = el.clientWidth || 560;
    const H = el.clientHeight || 150;
    const padL = 72, padR = 58, padT = 42, padB = 54;
    const innerW = W - padL - padR;
    const innerH = H - padT - padB;

    let yMin = Math.min(...loArr.filter(Number.isFinite), ...vArr.filter(Number.isFinite));
    let yMax = Math.max(...hiArr.filter(Number.isFinite), ...vArr.filter(Number.isFinite));

    if (!Number.isFinite(yMin) || !Number.isFinite(yMax)) {
      el.innerHTML = "";
      if (lastEl) lastEl.textContent = "--";
      return;
    }

    if (yMin === yMax) {
      yMin -= 1;
      yMax += 1;
    }

    const pad = (yMax - yMin) * 0.06;
    yMin -= pad;
    yMax += pad;

    if (yAxisLabel === "cm") yMin = Math.max(0, yMin);
    const x = (i) => padL + (i / (N - 1)) * innerW;
    const y = (val) => padT + (1 - (val - yMin) / (yMax - yMin)) * innerH;

    const fmtTime = (t) => {
      const d = new Date(t);
      if (isNaN(d.getTime())) return String(t);
      return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    };

    const buildPath = (arr) => {
      let d = "";
      for (let i = 0; i < N; i++) {
        const val = Number(arr[i]);
        if (!Number.isFinite(val)) continue;
        d += (d ? " L " : "M ") + `${x(i).toFixed(2)} ${y(val).toFixed(2)}`;
      }
      return d;
    };

    const lastVal = vArr[N - 1];
    if (lastEl) {
      lastEl.textContent = Number.isFinite(lastVal) ? `${lastVal.toFixed(2)}${unit}` : "--";
    }

    const yTicks = Array.from({ length: 5 }, (_, k) => yMin + (k / 4) * (yMax - yMin));
    const xIdx = [0, Math.floor((N - 1) / 2), N - 1];

    el.innerHTML = `
      <svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg">
        <text class="axis-unit axis-title axis-title-y" x="20" y="26" text-anchor="start">${yAxisLabel}</text>
        ${yTicks.map(tv => `
          <line x1="${padL}" y1="${y(tv)}" x2="${W - padR}" y2="${y(tv)}" stroke="rgba(255,255,255,0.08)" stroke-width="1"/>
          <text class="axis-tick axis-tick-y" x="${padL - 8}" y="${y(tv) + 4}" text-anchor="end" fill="rgba(210,225,245,0.78)" font-size="10" font-weight="700">${tv.toFixed(2)}</text>
        `).join("")}

        <path d="${buildPath(loArr)}" fill="none" stroke="rgba(125,196,255,0.82)" stroke-width="1.7" stroke-dasharray="4 4"></path>
        <path d="${buildPath(hiArr)}" fill="none" stroke="rgba(125,196,255,0.82)" stroke-width="1.7" stroke-dasharray="4 4"></path>
        <path d="${buildPath(vArr)}" fill="none" stroke="rgba(88,166,255,0.95)" stroke-width="2.4"></path>

        ${xIdx.map(i => `
          <text class="axis-tick axis-tick-x" x="${x(i)}" y="${H - 30}" text-anchor="middle" fill="rgba(210,225,245,0.78)" font-size="10" font-weight="700">${fmtTime(tArr[i])}</text>
        `).join("")}
        <text class="axis-unit axis-title axis-title-x" x="${(padL + W - padR) / 2}" y="${H - 8}" text-anchor="middle">Time</text>
      </svg>
    `;
  }

  function clearChart(chartSelector, lastSelector) {
    const chart = root.querySelector(chartSelector);
    if (chart) chart.innerHTML = "";
    const last = root.querySelector(lastSelector);
    if (last) last.textContent = "--";
  }

  function disableKpiCard(selector) {
    const el = root.querySelector(selector);
    const card = el ? el.closest(".kpi-card") : null;
    if (card) {
      card.classList.remove("kpi-green");
      card.classList.add("kpi-grey");
      card.style.opacity = "1";
    }
  }

  function disableKpiPanel(selector) {
    const el = root.querySelector(selector);
    const card = el ? el.closest(".kpi-card") : null;
    if (card) {
      card.classList.remove("kpi-green");
      card.classList.add("kpi-grey");
      card.classList.add("panel-disabled");
    }
  }

  function greyOutPanel(selector, opacity = "0.55") {
    const el = root.querySelector(selector);
    if (el) el.style.opacity = opacity;
  }

  // =========================
  // HEADER / TANK NAME
  // =========================
  setText("#tankName", btNo);

  // =========================
  // REAL LEVEL
  // =========================
  const levelField = getField(liveSeries, "level");
  const levelArr = getArray(levelField).map(Number).filter(Number.isFinite);
  const level = levelArr.length ? levelArr[levelArr.length - 1] : NaN;
  setText("#levelCm", Number.isFinite(level) ? level.toFixed(0) : "--");

  const tankFill = root.querySelector("#tankFill");
  if (tankFill) {
    const MAX_LEVEL = 460;
    const clamped = Number.isFinite(level) ? Math.max(0, Math.min(MAX_LEVEL, level)) : 0;
    const pct = (clamped / MAX_LEVEL) * 100;

    tankFill.style.height = `${pct.toFixed(1)}%`;
    tankFill.classList.remove("level-green", "level-yellow", "level-red");

    if (!Number.isFinite(level)) {
      tankFill.style.height = "0%";
    } else if (level > 80 && level < 460) {
      tankFill.classList.add("level-green");
    } else if (level <= 80) {
      tankFill.classList.add("level-red");
    } else {
      tankFill.classList.add("level-yellow");
    }
  }

  // =========================
  // GREY OUT QUALITY & INFO
  // =========================
  setText("#batchNo", "--");
  setText("#latexType", "--");
  setText("#supplyTank", "--");
  setText("#latexAge", "--");
  setText("#tsc", "--");
  setText("#stirrerHz", "--");

  disableKpiPanel("#batchNo");
  disableKpiPanel("#latexType");
  disableKpiPanel("#supplyTank");
  disableKpiPanel("#latexAge");
  disableKpiPanel("#tsc");
  disableKpiPanel("#stirrerHz");

  // =========================
  // DISABLE UNUSED CHARTS BUT KEEP DESIGN
  // =========================
  clearChart("#tscChartLeft", "#tscLastLeft");
  clearChart("#hzChartLeft", "#hzLastLeft");
  clearChart("#ageChart", "#ageLast");

  function disablePanel(chartSelector) {
    const chart = root.querySelector(chartSelector);
    if (!chart) return;

