      getField(trendSeries, "level") ||
      getField(trendSeries, "_value") ||   // ← ADD THIS HIGH PRIORITY
      getField(trendSeries, "mean") ||
      getField(trendSeries, "last");
    const times = getArray(timeField);
    const values = getArray(valueField).map(Number);

    const N = Math.min(times.length, values.length);
    const lo = Array.from({ length: N }, () => 0);
    const hi = Array.from({ length: N }, () => 460);

    if (N >= 2) {
      defer(() => renderMiniTrendWithAxis({
        el: root.querySelector("#levelChart"),
        times,
        value: values,
        min: lo,
        max: hi,
        lastEl: root.querySelector("#levelLast"),
