    if (cells[0]) cells[0].textContent = "--";
    if (cells[1]) cells[1].textContent = "--";
    if (cells[2]) cells[2].textContent = "--";
    if (cells[3]) cells[3].innerHTML = `<span class="pcd-chipval">-- Hr</span>`;
    if (cells[4]) cells[4].innerHTML = `<span class="pcd-chipval">--%</span>`;
    if (cells[5]) cells[5].innerHTML = `<span class="pcd-chipval">--</span>`;
